const blogs_track=document.querySelector(".blogs-cards"),blogs_slides=document.querySelectorAll(".blog-card");let blogsCurrentIndex=0;function getBlogSlidesPerView(){return window.innerWidth<=767?1:2}let blogs_slidesPerView=getBlogSlidesPerView();const totalblogslides=blogs_slides.length;function cloneBlogSlides(){for(let e=0;e<blogs_slidesPerView;e++){const l=blogs_slides[e].cloneNode(!0);blogs_track.appendChild(l)}}function showblogslide(e){const l=e*(100/blogs_slidesPerView);blogs_track.style.transform=`translateX(${l+9}%)`}function startblogslider(){setInterval(()=>{moveNextSlideblogs()},5e3)}function moveNextSlideblogs(){blogsCurrentIndex++,blogs_track.style.transition="transform 1s ease-in-out",showblogslide(blogsCurrentIndex),blogsCurrentIndex===totalblogslides&&setTimeout(()=>{blogs_track.style.transition="none",blogsCurrentIndex=0,showblogslide(blogsCurrentIndex)},1e3)}function movePrevSlideblogs(){blogsCurrentIndex--,blogsCurrentIndex<0&&(blogsCurrentIndex=totalblogslides-1),blogs_track.style.transition="transform 1s ease-in-out",showblogslide(blogsCurrentIndex)}cloneBlogSlides();let startXBlog=0,endXBlog=0;function handleSwipeblogs(){let e=startXBlog-endXBlog;Math.abs(e)>50&&(e>0?movePrevSlideblogs():moveNextSlideblogs())}blogs_track.addEventListener("touchstart",e=>{startXBlog=e.touches[0].clientX}),blogs_track.addEventListener("touchend",e=>{endXBlog=e.changedTouches[0].clientX,handleSwipe()}),startblogslider(),window.addEventListener("resize",()=>{blogs_slidesPerView=getBlogSlidesPerView()});